CREATE SCHEMA IF NOT EXISTS food_booking;

CREATE TABLE food_booking.users (
    user_id       BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    full_name     VARCHAR(150)        NOT NULL,
    email         VARCHAR(255)        NOT NULL UNIQUE,
    phone         VARCHAR(20)         NOT NULL UNIQUE,
    password_hash TEXT                NOT NULL,
    is_active     BOOLEAN             NOT NULL DEFAULT TRUE,
    is_verified   BOOLEAN             NOT NULL DEFAULT FALSE,
    created_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.addresses (
    address_id   BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    user_id      BIGINT              NOT NULL REFERENCES food_booking.users(user_id) ON DELETE CASCADE,
    label        VARCHAR(50)         NOT NULL DEFAULT 'Home',
    address_line TEXT                NOT NULL,
    city         VARCHAR(100)        NOT NULL,
    state        VARCHAR(100)        NOT NULL,
    postal_code  VARCHAR(20)         NOT NULL,
    country      VARCHAR(100)        NOT NULL DEFAULT 'US',
    latitude     NUMERIC(9,6),
    longitude    NUMERIC(9,6),
    is_default   BOOLEAN             NOT NULL DEFAULT FALSE,
    created_at   TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.restaurants (
    restaurant_id   BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    name            VARCHAR(200)        NOT NULL,
    slug            VARCHAR(200)        NOT NULL UNIQUE,
    description     TEXT,
    email           VARCHAR(255)        NOT NULL UNIQUE,
    phone           VARCHAR(20)         NOT NULL,
    address_line    TEXT                NOT NULL,
    city            VARCHAR(100)        NOT NULL,
    state           VARCHAR(100)        NOT NULL,
    postal_code     VARCHAR(20)         NOT NULL,
    country         VARCHAR(100)        NOT NULL DEFAULT 'US',
    latitude        NUMERIC(9,6),
    longitude       NUMERIC(9,6),
    cuisine_type    VARCHAR(100),
    opening_time    TIME                NOT NULL DEFAULT '08:00:00',
    closing_time    TIME                NOT NULL DEFAULT '22:00:00',
    avg_rating      NUMERIC(3,2)        NOT NULL DEFAULT 0.00,
    is_active       BOOLEAN             NOT NULL DEFAULT TRUE,
    is_verified     BOOLEAN             NOT NULL DEFAULT FALSE,
    created_at      TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.menus (
    menu_id       BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    restaurant_id BIGINT              NOT NULL REFERENCES food_booking.restaurants(restaurant_id) ON DELETE CASCADE,
    name          VARCHAR(150)        NOT NULL,
    description   TEXT,
    is_active     BOOLEAN             NOT NULL DEFAULT TRUE,
    created_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.menu_categories (
    category_id   BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    menu_id       BIGINT              NOT NULL REFERENCES food_booking.menus(menu_id) ON DELETE CASCADE,
    name          VARCHAR(150)        NOT NULL,
    description   TEXT,
    sort_order    INT                 NOT NULL DEFAULT 0,
    created_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.menu_items (
    item_id       BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    category_id   BIGINT              NOT NULL REFERENCES food_booking.menu_categories(category_id) ON DELETE CASCADE,
    restaurant_id BIGINT              NOT NULL REFERENCES food_booking.restaurants(restaurant_id) ON DELETE CASCADE,
    name          VARCHAR(200)        NOT NULL,
    description   TEXT,
    price         NUMERIC(10,2)       NOT NULL CHECK (price >= 0),
    image_url     TEXT,
    is_vegetarian BOOLEAN             NOT NULL DEFAULT FALSE,
    is_vegan      BOOLEAN             NOT NULL DEFAULT FALSE,
    is_gluten_free BOOLEAN            NOT NULL DEFAULT FALSE,
    is_available  BOOLEAN             NOT NULL DEFAULT TRUE,
    sort_order    INT                 NOT NULL DEFAULT 0,
    created_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.coupons (
    coupon_id       BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    code            VARCHAR(50)         NOT NULL UNIQUE,
    description     TEXT,
    discount_type   VARCHAR(20)         NOT NULL CHECK (discount_type IN ('percentage', 'fixed')),
    discount_value  NUMERIC(10,2)       NOT NULL CHECK (discount_value > 0),
    min_order_value NUMERIC(10,2)       NOT NULL DEFAULT 0.00,
    max_discount    NUMERIC(10,2),
    usage_limit     INT,
    used_count      INT                 NOT NULL DEFAULT 0,
    valid_from      TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    valid_until     TIMESTAMPTZ         NOT NULL,
    is_active       BOOLEAN             NOT NULL DEFAULT TRUE,
    created_at      TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.orders (
    order_id          BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    user_id           BIGINT              NOT NULL REFERENCES food_booking.users(user_id),
    restaurant_id     BIGINT              NOT NULL REFERENCES food_booking.restaurants(restaurant_id),
    address_id        BIGINT              NOT NULL REFERENCES food_booking.addresses(address_id),
    coupon_id         BIGINT              REFERENCES food_booking.coupons(coupon_id),
    status            VARCHAR(30)         NOT NULL DEFAULT 'pending'
                                          CHECK (status IN ('pending','confirmed','preparing','out_for_delivery','delivered','cancelled')),
    subtotal          NUMERIC(10,2)       NOT NULL DEFAULT 0.00,
    discount_amount   NUMERIC(10,2)       NOT NULL DEFAULT 0.00,
    delivery_fee      NUMERIC(10,2)       NOT NULL DEFAULT 0.00,
    tax_amount        NUMERIC(10,2)       NOT NULL DEFAULT 0.00,
    total_amount      NUMERIC(10,2)       NOT NULL DEFAULT 0.00,
    special_instructions TEXT,
    estimated_delivery_time TIMESTAMPTZ,
    delivered_at      TIMESTAMPTZ,
    created_at        TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.order_items (
    order_item_id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    order_id      BIGINT              NOT NULL REFERENCES food_booking.orders(order_id) ON DELETE CASCADE,
    item_id       BIGINT              NOT NULL REFERENCES food_booking.menu_items(item_id),
    item_name     VARCHAR(200)        NOT NULL,
    unit_price    NUMERIC(10,2)       NOT NULL,
    quantity      INT                 NOT NULL CHECK (quantity > 0),
    line_total    NUMERIC(10,2)       GENERATED ALWAYS AS (unit_price * quantity) STORED,
    special_notes TEXT,
    created_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.payments (
    payment_id       BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    order_id         BIGINT              NOT NULL REFERENCES food_booking.orders(order_id),
    payment_method   VARCHAR(50)         NOT NULL CHECK (payment_method IN ('credit_card','debit_card','paypal','wallet','cash_on_delivery')),
    status           VARCHAR(30)         NOT NULL DEFAULT 'pending'
                                         CHECK (status IN ('pending','completed','failed','refunded')),
    amount           NUMERIC(10,2)       NOT NULL,
    transaction_id   VARCHAR(255)        UNIQUE,
    paid_at          TIMESTAMPTZ,
    created_at       TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at       TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.delivery_agents (
    agent_id      BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    full_name     VARCHAR(150)        NOT NULL,
    email         VARCHAR(255)        NOT NULL UNIQUE,
    phone         VARCHAR(20)         NOT NULL UNIQUE,
    vehicle_type  VARCHAR(50)         NOT NULL CHECK (vehicle_type IN ('bike','scooter','car','bicycle')),
    is_available  BOOLEAN             NOT NULL DEFAULT TRUE,
    is_active     BOOLEAN             NOT NULL DEFAULT TRUE,
    avg_rating    NUMERIC(3,2)        NOT NULL DEFAULT 0.00,
    created_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.deliveries (
    delivery_id       BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    order_id          BIGINT              NOT NULL UNIQUE REFERENCES food_booking.orders(order_id),
    agent_id          BIGINT              REFERENCES food_booking.delivery_agents(agent_id),
    status            VARCHAR(30)         NOT NULL DEFAULT 'pending'
                                          CHECK (status IN ('pending','assigned','picked_up','on_the_way','delivered','failed')),
    picked_up_at      TIMESTAMPTZ,
    delivered_at      TIMESTAMPTZ,
    delivery_notes    TEXT,
    created_at        TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMPTZ         NOT NULL DEFAULT NOW()
);

CREATE TABLE food_booking.reviews (
    review_id     BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    user_id       BIGINT              NOT NULL REFERENCES food_booking.users(user_id),
    restaurant_id BIGINT              NOT NULL REFERENCES food_booking.restaurants(restaurant_id),
    order_id      BIGINT              NOT NULL REFERENCES food_booking.orders(order_id),
    rating        SMALLINT            NOT NULL CHECK (rating BETWEEN 1 AND 5),
    comment       TEXT,
    created_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    UNIQUE (user_id, order_id)
);

CREATE TABLE food_booking.agent_reviews (
    agent_review_id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    user_id         BIGINT              NOT NULL REFERENCES food_booking.users(user_id),
    agent_id        BIGINT              NOT NULL REFERENCES food_booking.delivery_agents(agent_id),
    order_id        BIGINT              NOT NULL REFERENCES food_booking.orders(order_id),
    rating          SMALLINT            NOT NULL CHECK (rating BETWEEN 1 AND 5),
    comment         TEXT,
    created_at      TIMESTAMPTZ         NOT NULL DEFAULT NOW(),
    UNIQUE (user_id, order_id)
);

