-- Reusable trigger function to auto-update updated_at
CREATE OR REPLACE FUNCTION food_booking.set_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$;

