-- Function to auto-update restaurant avg_rating after a review insert/update/delete
CREATE OR REPLACE FUNCTION food_booking.refresh_restaurant_rating()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
    UPDATE food_booking.restaurants
    SET avg_rating = (
        SELECT COALESCE(AVG(rating), 0)
        FROM food_booking.reviews
        WHERE restaurant_id = COALESCE(NEW.restaurant_id, OLD.restaurant_id)
    )
    WHERE restaurant_id = COALESCE(NEW.restaurant_id, OLD.restaurant_id);
    RETURN NULL;
END;
$$;

CREATE TRIGGER trg_refresh_restaurant_rating
    AFTER INSERT OR UPDATE OR DELETE ON food_booking.reviews
    FOR EACH ROW EXECUTE FUNCTION food_booking.refresh_restaurant_rating();

-- Function to auto-update delivery agent avg_rating after an agent review insert/update/delete
CREATE OR REPLACE FUNCTION food_booking.refresh_agent_rating()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
    UPDATE food_booking.delivery_agents
    SET avg_rating = (
        SELECT COALESCE(AVG(rating), 0)
        FROM food_booking.agent_reviews
        WHERE agent_id = COALESCE(NEW.agent_id, OLD.agent_id)
    )
    WHERE agent_id = COALESCE(NEW.agent_id, OLD.agent_id);
    RETURN NULL;
END;
$$;

CREATE TRIGGER trg_refresh_agent_rating
    AFTER INSERT OR UPDATE OR DELETE ON food_booking.agent_reviews
    FOR EACH ROW EXECUTE FUNCTION food_booking.refresh_agent_rating();

-- View: restaurant summary with avg rating and total orders
CREATE OR REPLACE VIEW food_booking.v_restaurant_summary AS
SELECT
    r.restaurant_id,
    r.name,
    r.slug,
    r.cuisine_type,
    r.city,
    r.avg_rating,
    COUNT(DISTINCT o.order_id)  AS total_orders,
    COUNT(DISTINCT rv.review_id) AS total_reviews,
    r.is_active,
    r.opening_time,
    r.closing_time
FROM food_booking.restaurants r
LEFT JOIN food_booking.orders o ON o.restaurant_id = r.restaurant_id
LEFT JOIN food_booking.reviews rv ON rv.restaurant_id = r.restaurant_id
GROUP BY r.restaurant_id;

-- View: order summary with user, restaurant, payment and delivery info
CREATE OR REPLACE VIEW food_booking.v_order_summary AS
SELECT
    o.order_id,
    u.full_name        AS customer_name,
    u.email            AS customer_email,
    r.name             AS restaurant_name,
    o.status           AS order_status,
    o.subtotal,
    o.discount_amount,
    o.delivery_fee,
    o.tax_amount,
    o.total_amount,
    p.payment_method,
    p.status           AS payment_status,
    d.status           AS delivery_status,
    da.full_name       AS delivery_agent,
    o.created_at
FROM food_booking.orders o
JOIN food_booking.users u ON u.user_id = o.user_id
JOIN food_booking.restaurants r ON r.restaurant_id = o.restaurant_id
LEFT JOIN food_booking.payments p ON p.order_id = o.order_id
LEFT JOIN food_booking.deliveries d ON d.order_id = o.order_id
LEFT JOIN food_booking.delivery_agents da ON da.agent_id = d.agent_id;

-- View: menu item details with category and restaurant info
CREATE OR REPLACE VIEW food_booking.v_menu_item_details AS
SELECT
    mi.item_id,
    r.name             AS restaurant_name,
    m.name             AS menu_name,
    mc.name            AS category_name,
    mi.name            AS item_name,
    mi.description,
    mi.price,
    mi.is_vegetarian,
    mi.is_vegan,
    mi.is_gluten_free,
    mi.is_available
FROM food_booking.menu_items mi
JOIN food_booking.menu_categories mc ON mc.category_id = mi.category_id
JOIN food_booking.menus m ON m.menu_id = mc.menu_id
JOIN food_booking.restaurants r ON r.restaurant_id = mi.restaurant_id;
